INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('35','BrowserElement.scroll','{"key": "BrowserElement.scroll", "title": "웹 페이지 스크롤", "version": "1.0.5", "src": "astronverse.browser.browser_element.BrowserElement().scroll", "comment": "항목 @{scroll_direction:항목/항목} 의, 항목(@{x_scroll_type||y_scroll_type})브라우저 객체 @{browser_obj} 의", "inputList": [{"types": "Browser", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "browser_obj", "title": "브라우저 객체", "name": "browser_obj", "tip": "선택의페이지에서브라우저 객체", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "ScrollbarType", "formType": {"type": "RADIO"}, "key": "scrollbar_type", "title": "목록", "name": "scrollbar_type", "tip": "선택페이지또는지정페이지위개요소", "options": [{"label": "항목", "value": "window"}, {"label": "자동목록", "value": "customEle"}], "default": "window", "required": true}, {"types": "WebPick", "formType": {"type": "PICK", "params": {"use": "WebPick"}}, "key": "element_data", "title": "가져오기", "name": "element_data", "tip": "가져오기필요에서페이지위의요소", "dynamics": [{"key": "$this.element_data.show", "expression": "return $this.scrollbar_type.value == ''customEle''"}], "required": true, "noInput": true}, {"types": "ScrollDirection", "formType": {"type": "RADIO"}, "key": "scroll_direction", "title": "항목", "name": "scroll_direction", "tip": "", "options": [{"label": "항목", "value": "horizontal"}, {"label": "항목", "value": "vertical"}], "default": "horizontal", "required": true}, {"types": "ScrollbarForXScrollTypeFlag", "formType": {"type": "RADIO"}, "key": "x_scroll_type", "title": "위치", "name": "x_scroll_type", "tip": "", "options": [{"label": "왼쪽", "value": "left"}, {"label": "오른쪽", "value": "right"}, {"label": "자동", "value": "defined"}], "default": "left", "dynamics": [{"key": "$this.x_scroll_type.show", "expression": "return $this.scroll_direction.value == ''horizontal''"}], "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key":