heck.value == true"}], "required": false}, {"types": "DefaultButtonC", "formType": {"type": "SELECT"}, "key": "default_button_c", "title": "시기본선택중버튼", "name": "default_button_c", "tip": "", "options": [{"label": "항목", "value": "confirm"}], "default": "confirm", "dynamics": [{"key": "$this.default_button_c.show", "expression": "return $this.auto_check.value == true && $this.button_type.value == ''confirm''"}], "required": true}, {"types": "DefaultButtonCN", "formType": {"type": "SELECT"}, "key": "default_button_cn", "title": "시기본선택중버튼", "name": "default_button_cn", "tip": "", "options": [{"label": "항목", "value": "confirm"}, {"label": "가져오기", "value": "cancel"}], "default": "confirm", "dynamics": [{"key": "$this.default_button_cn.show", "expression": "return $this.auto_check.value == true && $this.button_type.value == ''confirm_cancel''"}], "required": true}, {"types": "DefaultButtonY", "formType": {"type": "SELECT"}, "key": "default_button_y", "title": "시기본선택중버튼", "name": "default_button_y", "tip": "", "options": [{"label": "예", "value": "yes"}, {"label": "아니오", "value": "no"}], "default": "yes", "dynamics": [{"key": "$this.default_button_y.show", "expression": "return $this.auto_check.value == true && $this.button_type.value == ''yes_no''"}], "required": true}, {"types": "DefaultButtonYN", "formType": {"type": "SELECT"}, "key": "default_button_yn", "title": "시기본선택중버튼", "name": "default_button_yn", "tip": "", "options": [{"label": "예", "value": "yes"}, {"label": "아니오", "value": "no"}, {"label": "가져오기", "value": "cancel"}], "default": "yes", "dynamics": [{"key": "$this.default_button_yn.show", "expression": "return $this.auto_check.value == true && $this.button_type.value == ''yes_no_cancel''"}], "required": true}, {"types": "Any", "formType": {"type": "MODALBUTTON"}, "key": "preview_button", "title": "항목", "name": "preview_button", "tip": "", "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "result_button", "title": "저장사용자선택