INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('116','Docx.close_docx','{"key": "Docx.close_docx", "title": "닫기Word", "version": "1.0.2", "src": "astronverse.word.docx.Docx().close_docx", "comment": "닫기Word객체 @{doc}", "inputList": [{"types": "DocumentObject", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "doc", "title": "Word객체", "name": "doc", "tip": "앞(열기, 생성)의Word객체", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "CloseRangeType", "formType": {"type": "RADIO"}, "key": "close_range_flag", "title": "닫기문서", "name": "close_range_flag", "tip": "선택닫기문서의, 닫기앞문서또는닫기문서", "options": [{"label": "닫기앞문서", "value": "one"}, {"label": "닫기문서", "value": "all"}], "default": "one", "required": true}, {"types": "SaveType", "formType": {"type": "RADIO"}, "key": "save_type", "title": "저장유형", "name": "save_type", "tip": "선택저장유형, 저장, 저장로, 안저장", "options": [{"label": "저장", "value": "save"}, {"label": "저장로", "value": "save_as"}, {"label": "안저장", "value": "abort"}], "default": "save", "dynamics": [{"key": "$this.save_type.show", "expression": "return $this.close_range_flag.value == ''one''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "file_path", "title": "저장로문서경로", "name": "file_path", "tip": "입력쓰기Word의저장경로", "default": "", "dynamics": [{"key": "$this.file_path.show", "expression": "return $this.save_type.value == ''save_as'' && $this.close_range_flag.value == ''one''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "file_name", "title": "저장로문서이름", "name": "file_name", "tip": "입력쓰기Word의이름", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.file_name.show", "expression": "return $this.save_type.value == ''save_as'' && $this.close_range_flag.value == ''one''"}], "required": true}, {"types": "FileExistenceType", "formType"