INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('189','File.file_search','{"key": "File.file_search", "title": "파일", "version": "1.0.1", "src": "astronverse.system.file.File().file_search", "comment": "에서 @{folder_path} 목록중파일명 @{search_pattern} 의파일, 및저장파일 경로변수 @{find_file_result}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "folder_path", "title": "대기파일에서목록", "name": "folder_path", "tip": "선택또는출력입력대기파일에서목록", "default": "", "required": true}, {"types": "SearchType", "formType": {"type": "RADIO"}, "key": "find_type", "title": "방식", "name": "find_type", "tip": "지정방식: 필요출력입력파일명;모듈출력입력부분파일명, 필요영역대형소쓰기;표출력입력표", "options": [{"label": "항목", "value": "exact"}, {"label": "모듈", "value": "fuzzy"}, {"label": "표", "value": "regex"}], "default": "fuzzy", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "search_pattern", "title": "파일명", "name": "search_pattern", "tip": "출력입력내용", "default": "", "required": true}, {"types": "TraverseType", "formType": {"type": "RADIO"}, "key": "traverse_subfolder", "title": "폴더", "name": "traverse_subfolder", "tip": "여부 선택폴더", "options": [{"label": "목록", "value": "yes"}, {"label": "안목록", "value": "no"}], "default": "no", "required": false}], "outputList": [{"types": "List", "formType": {"type": "RESULT"}, "key": "find_file_result", "title": "저장결과", "tip": "출력파일 경로목록, 및저장까지변수, 수데이터유형로목록"}], "icon": "find-file", "helpManual": "에서지정목록중파일명지정내용의파일, 및출력파일목록변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('190','File.file_wait_status','{"key": "File.file_wait_status", "title": "등대기파일", "version": "1.0.1", "src": "astronverse.system.file.File().file_wait_status", "comment": "등대기파일 @{file_path} 상태로 @{status_type} 시집행행아래, 저장등대기결과까지 @{wait_file_result}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "file"}}, "key": "file_path", "title": "파일 경로", "name": "file_path", "tip": "선택또는출력입력파일 경로", "default": "", "required": true}, {"types": "StatusType", "formType": {"type": "RADIO"}, "key": "status_type", "title": "등대기상태", "name": "status_type", "tip": "선택등대기파일의상태", "options": [{"label": "생성", "value": "created"}, {"label": "삭제", "value": "deleted"}], "default": "created", "required": false}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "wait_time", "title": "시시간", "name": "wait_time", "tip": "설정등대기시시간, 단일위치로초", "default": 10, "value": [{"type": "str", "value": ""}], "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "wait_file_result", "title": "저장등대기결과", "tip": "출력등대기결과변수, 수데이터유형로불리언 값"}], "icon": "wait-file", "helpManual": "등대기파일상태로지정상태시집행행아래, 및출력등대기결과변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('191','File.file_write','{"key": "File.file_write", "title": "쓰기파일", "version": "1.0.1", "src": "astronverse.system.file.File().file_write", "comment": "쓰기내용 @{msg} 까지파일 @{file_path} 중, 및저장쓰기뒤의파일 경로 @{write_file_path}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "file"}}, "key": "file_path", "title": "파일 경로", "name": "file_path", "tip": "선택또는출력입력파일 경로, 쓰기의파일 유형: \\".txt\\",  \\".docx\\",  \\".md\\",  \\".py\\",  \\".json\\",  \\".csv\\"", "default": "", "required": true}, {"types": "StateType", "formType": {"type": "RADIO"}, "key": "file_option", "title": "파일안저장에서시", "name": "file_option", "tip": "선택파일안저장에서시집행행의", "options": [{"label": "생성", "value": "create"}, {"label": "및오류", "value": "error"}], "default": "error", "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "msg", "title": "쓰기내용", "name": "msg", "tip": "출력입력쓰기의내용", "default": "", "required": true}, {"types": "WriteType", "formType": {"type": "RADIO"}, "key": "write_type", "title": "쓰기방식", "name": "write_type", "tip": "지정쓰기방식", "options": [{"label": "쓰기", "value": "overwrite"}, {"label": "쓰기", "value": "append"}], "default": "append", "required": false}, {"types": "EncodeType", "formType": {"type": "SELECT"}, "key": "encode_type", "title": "코드방식", "name": "encode_type", "tip": "선택쓰기내용의코드방식, 파일내용로빈시필요지정, 기본선택항목시자동대기쓰기파일의코드방식", "options": [{"label": "기본", "value": "default"}, {"label": "ansi", "value": "ansi"}, {"label": "utf-8", "value": "utf-8"}, {"label": "utf-16", "value": "utf-16"}, {"label": "utf-16 be", "value": "utf-16 be"}, {"label": "gbk", "value": "gbk"}, {"label": "gb2312", "value": "gb2312"}, {"label": "gb18030", "value": "gb18030"}], "default": "default", "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "write_file_path", "title": "파일 경로", "tip": "출력쓰기뒤파일 경로변수, 수데이터유형로문자열"}], "icon": "write-file", "helpManual": "지정파일중쓰기내용, 및출력쓰기뒤의파일 경로변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('192','File.get_file_encoding_type','{"key": "File.get_file_encoding_type", "title": "가져오기파일코드유형", "version": "1.0.1", "src": "astronverse.system.file.File().get_file_encoding_type", "comment": "가져오기파일 @{file_path} 의코드유형및저장변수 @{file_encoding_type}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "file"}}, "key": "file_path", "title": "파일 경로", "name": "file_path", "tip": "선택또는출력입력대기가져오기코드유형의파일 경로", "default": "", "required": true}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "file_encoding_type", "title": "파일코드유형", "tip": "출력파일코드유형변수, 수데이터유형로문자열"}], "icon": "get-file-encoding", "helpManual": "가져오기지정파일의코드유형, 및출력코드유형변수"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('193','File.get_file_list','{"key": "File.get_file_list", "title": "가져오기파일목록", "version": "1.0.1", "src": "astronverse.system.file.File().get_file_list", "comment": "가져오기지정목록 @{folder_path} 중의파일목록, 및저장파일목록변수 @{file_list}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "folder_path", "title": "파일목록", "name": "folder_path", "tip": "선택또는출력입력파일목록경로", "default": "", "required": true}, {"types": "TraverseType", "formType": {"type": "RADIO"}, "key": "traverse_subfolder", "title": "목록", "name": "traverse_subfolder", "tip": "여부 선택목록", "options": [{"label": "목록", "value": "yes"}, {"label": "안목록", "value": "no"}], "default": "no", "required": true}, {"types": "Bool", "formType": {"type": "SWITCH", "params": {}}, "key": "tempfile_include", "title": "예아니오시파일", "name": "tempfile_include", "tip": "여부 선택시파일, 항목~,~$열기또는.tmp의파일", "options": [{"label": "예", "value": true}, {"label": "아니오", "value": false}], "default": true, "required": true}, {"types": "OutputType", "formType": {"type": "RADIO"}, "key": "output_type", "title": "출력방식", "name": "output_type", "tip": "설정출력방식", "options": [{"label": "목록출력", "value": "list"}, {"label": "저장까지표파일", "value": "excel"}], "default": "list", "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "excel_path", "title": "Excel저장목록", "name": "excel_path", "tip": "선택또는출력입력저장의Excel저장목록", "default": "", "dynamics": [{"key": "$this.excel_path.show", "expression": "return $this.output_type.value == ''excel''"}], "required": true}, {"types": "StateType", "formType": {"type": "RADIO"}, "key": "state_type", "title": "목록안저장에서시", "name": "state_type", "tip": "선택Excel저장목록안저장에서시집행행의", "options": [{"label": "생성", "value": "create"}, {"label": "및오류", "value": "error"}], "defau