INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('203','Gui.keyboard','{"key": "Gui.keyboard", "title": "키보드 입력", "version": "1.0.1", "src": "astronverse.input.gui_key.GuiKeyBoard().keyboard", "comment": "항목(@{keyboard_type})방식모듈키보드 입력(@{message})", "inputList": [{"types": "KeyboardType", "formType": {"type": "SELECT"}, "key": "keyboard_type", "title": "출력입력방식", "name": "keyboard_type", "tip": "출력입력: windows키보드의방식키 입력 시뮬레이션출력입력;템플릿출력입력: 가져오기템플릿내용및출력입력;키계약: 입력키보드번호계약출력입력;출력입력: 키 입력 시뮬레이션출력입력, 코드상자출력입력또는출력입력방식없음출력입력의", "options": [{"label": "출력입력", "value": "normal"}, {"label": "출력입력", "value": "driver"}, {"label": "템플릿출력입력", "value": "clip"}, {"label": "ghost출력입력", "value": "gblid"}], "default": "normal", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "message", "title": "출력입력내용", "name": "message", "tip": "", "default": "", "dynamics": [{"key": "$this.message.show", "expression": "return [''normal'', ''driver'', ''gblid''].includes($this.keyboard_type.value)"}], "required": true}, {"types": "Simulate_flag", "formType": {"type": "RADIO"}, "key": "simulate_flag", "title": "모듈출력입력", "name": "simulate_flag", "tip": "모듈방식키보드개출력입력, 기본로아니오", "options": [{"label": "예", "value": "yes"}, {"label": "아니오", "value": "no"}], "default": "no", "dynamics": [{"key": "$this.simulate_flag.show", "expression": "return $this.keyboard_type.value == ''normal''"}], "required": true}, {"types": "Float", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "interval", "title": "출력입력간", "name": "interval", "tip": "설정출력입력간, 단일위치로초", "default": 0.1, "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.interval.show", "expression": "return [''normal'', ''driver''].includes($this.keyboard_type.value)"}], "required": true}], "outputList": [], "icon": "keyboard-input", "helpManual": ""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
