INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('205','Gui.mouse','{"key": "Gui.mouse", "title": "마우스 클릭", "version": "1.0.1", "src": "astronverse.input.gui_mouse.GuiMouse().mouse", "comment": "모듈마우스(@{btn_type:왼쪽키/오른쪽키/중키}) (@{btn_model:아래/항목/단일기계/더블 클릭}))", "inputList": [{"types": "BtnType", "formType": {"type": "RADIO"}, "key": "btn_type", "title": "마우스키", "name": "btn_type", "tip": "선택마우스위의키위치", "options": [{"label": "왼쪽키", "value": "left"}, {"label": "중키", "value": "middle"}, {"label": "오른쪽키", "value": "right"}], "default": "left", "required": true}, {"types": "BtnModel", "formType": {"type": "SELECT"}, "key": "btn_model", "title": "방식", "name": "btn_model", "tip": "선택마우스의방식", "options": [{"label": "단일", "value": "click"}, {"label": "더블 클릭", "value": "double_click"}, {"label": "아래", "value": "down"}, {"label": "항목", "value": "up"}], "default": "click", "required": true}, {"types": "ControlType", "formType": {"type": "SELECT"}, "key": "ctrl_type", "title": "키보드키", "name": "ctrl_type", "tip": "선택키보드키, 기본로없음", "options": [{"label": "없음", "value": "none"}, {"label": "ctrl", "value": "ctrl"}, {"label": "alt", "value": "alt"}, {"label": "shift", "value": "shift"}, {"label": "win", "value": "win"}, {"label": "space", "value": "space"}], "default": "none", "required": true}], "outputList": [], "icon": "mouse-click", "helpManual": ""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:16');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('206','Gui.mouse_drag','{"key": "Gui.mouse_drag", "title": "마우스 드래그", "version": "1.0.1", "src": "astronverse.input.gui_mouse.GuiMouse().mouse_drag", "comment": "모듈마우스위치(@{start_pos_x}, @{start_pos_y})드래그까지위치(@{end_pos_x}, @{end_pos_y})", "inputList": [{"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "start_pos_x", "title": "마우스x위치", "name": "start_pos_x", "tip": "", "default": 0, "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "start_pos_y", "title": "마우스y위치", "name": "start_pos_y", "tip": "", "default": 0, "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "end_pos_x", "title": "마우스x위치", "name": "end_pos_x", "tip": "", "default": 0, "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON", "params": {"size": "middle"}}, "key": "end_pos_y", "title": "마우스y위치", "name": "end_pos_y", "tip": "", "default": 0, "required": true}, {"types": "BtnType", "formType": {"type": "RADIO"}, "key": "btn_type", "title": "마우스키", "name": "btn_type", "tip": "드래그시아래의마우스키위치", "options": [{"label": "왼쪽키", "value": "left"}, {"label": "중키", "value": "middle"}, {"label": "오른쪽키", "value": "right"}], "default": "left", "required": true}, {"types": "MoveType", "formType": {"type": "RADIO"}, "key": "move_type", "title": "방식", "name": "move_type", "tip": "선택마우스 이동방식", "options": [{"label": "항목", "value": "linear"}, {"label": "모듈방식", "value": "simulation"}, {"label": "시", "value": "teleportation"}], "default": "linear", "required": true}, {"types": "Speed", "formType": {"type": "RADIO"}, "key": "move_speed", "title": "항목", "name": "move_speed", "tip": "선택마우스 이동", "options": [{"label": "항목", "value": "slow"}, {"label": "예외", "value": "normal"}, {"label": "항목", "value": "fast"}], "d