INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('225','MathProcess.calculate_expression','{"key": "MathProcess.calculate_expression", "title": "수식 계산", "version": "1.0.2", "src": "astronverse.dataprocess.math.MathProcess().calculate_expression", "comment": "행의수식 계산 @{left}  @{operator}  @{right} , 계산결과 @{calculation_number}", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "left", "title": "계산왼쪽값", "name": "left", "tip": "", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "MathOperatorType", "formType": {"type": "SELECT"}, "key": "operator", "title": "계산", "name": "operator", "tip": "", "options": [{"label": "항목", "value": "+"}, {"label": "감소", "value": "-"}, {"label": "항목", "value": "*"}, {"label": "항목", "value": "/"}], "default": "+", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "right", "title": "계산오른쪽값", "name": "right", "tip": "", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "MathRoundType", "formType": {"type": "SELECT"}, "key": "handle_method", "title": "반환값처리방식", "name": "handle_method", "tip": "", "options": [{"label": "입력", "value": "round"}, {"label": "위가져오기", "value": "ceil"}, {"label": "아래가져오기", "value": "floor"}, {"label": "안", "value": "none"}], "default": "none", "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "precision", "title": "입력위치수", "name": "precision", "tip": "", "default": 0, "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.precision.show", "expression": "return $this.handle_method.value == ''round''"}], "required": true}], "outputList": [{"types": "Any", "formType": {"type": "RESULT"}, "key": "calculation_number", "title": "계산결과", "tip": ""}], "icon": "math-calculation", "helpManual": ""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('226','MathProcess.generate_random_number','{"key": "MathProcess.generate_random_number", "title": "난수 생성", "version": "1.0.2", "src": "astronverse.dataprocess.math.MathProcess().generate_random_number", "comment": "생성 @{number_type} 유형 @{size} 개기계수, 로 @{start} 까지 @{end} , 생성의기계수 @{generated_random_numbers}", "inputList": [{"types": "NumberType", "formType": {"type": "RADIO"}, "key": "number_type", "title": "기계수유형", "name": "number_type", "tip": "", "options": [{"label": "정수", "value": "integer"}, {"label": "수", "value": "float"}], "default": "integer", "required": true}, {"types": "Int", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "size", "title": "기계수개수", "name": "size", "tip": "", "default": 1, "value": [{"type": "str", "value": ""}], "required": false}, {"types": "Float", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "start", "title": "열기", "name": "start", "tip": "", "default": 0, "value": [{"type": "str", "value": ""}], "required": true}, {"types": "Float", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "end", "title": "항목", "name": "end", "tip": "", "default": 101, "value": [{"type": "str", "value": ""}], "required": true}], "outputList": [{"types": "Any", "formType": {"type": "RESULT"}, "key": "generated_random_numbers", "title": "생성의기계수", "tip": ""}], "icon": "generate-random-number", "helpManual": ""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
