INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('231','Network.create_folder','{"key": "Network.create_folder", "title": "생성폴더(FTP)", "version": "1.0.1", "src": "astronverse.network.ftp.FTP().create_folder", "comment": "에서지정FTP연결(@{ftp_instance})아래생성폴더(@{folder_name}),및저장새폴더 경로까지(@{new_folder})중", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "ftp_instance", "title": "FTP연결객체", "name": "ftp_instance", "tip": "필요생성폴더의FTP연결객체", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "folder_name", "title": "새폴더이름", "name": "folder_name", "tip": "필요생성의폴더이름", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "FileExistenceType", "formType": {"type": "SELECT"}, "key": "exist_type", "title": "폴더 존재시", "name": "exist_type", "tip": "항목FTP연결아래저장에서폴더시필요집행행의", "options": [{"label": "생성파일", "value": "rename"}, {"label": "파일", "value": "overwrite"}, {"label": "건너뛰기저장", "value": "cancel"}], "default": "rename", "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "new_folder", "title": "생성뒤폴더 경로", "tip": "생성뒤의폴더 경로저장변수"}], "icon": "create-folder", "helpManual": "에서지정FTP연결아래생성폴더"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
