INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('234','Network.ftp_delete','{"key": "Network.ftp_delete", "title": "삭제파일/폴더(FTP)", "version": "1.0.1", "src": "astronverse.network.ftp.FTP().ftp_delete", "comment": "삭제(@{ftp_instance})위(@{delete_file_name||delete_folder_name}),및출력삭제결과변수(@{delete_ftp_result})", "inputList": [{"types": "Any", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "ftp_instance", "title": "FTP연결객체", "name": "ftp_instance", "tip": "집행행파일/폴더삭제의FTP연결객체", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "FileType", "formType": {"type": "RADIO"}, "key": "file_type", "title": "삭제객체", "name": "file_type", "tip": "", "options": [{"label": "파일", "value": "file"}, {"label": "폴더", "value": "folder"}], "default": "file", "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "delete_file_name", "title": "대기삭제파일", "name": "delete_file_name", "tip": "단일개또는다중개파일삭제,다중개파일명간번호열기,항목:test1.txt,test2.txt,test3.txt", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.delete_file_name.show", "expression": "return $this.file_type.value == ''file''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "delete_folder_name", "title": "대기삭제폴더", "name": "delete_folder_name", "tip": "단일개또는다중개폴더삭제,다중개폴더간번호열기,항목:folder1,folder2,folder3", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.delete_folder_name.show", "expression": "return $this.file_type.value == ''folder''"}], "required": true}], "outputList": [{"types": "Bool", "formType": {"type": "RESULT"}, "key": "delete_ftp_result", "title": "삭제결과", "tip": "출력삭제결과까지변수,수데이터유형로불리언 값"}], "icon": "delete-folder-ftp", "helpManual": "삭제FTP기중지정파일/폴더"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
