INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('236','Network.ftp_rename','{"key": "Network.ftp_rename", "title": "파일/폴더(FTP)", "version": "1.0.1", "src": "astronverse.network.ftp.FTP().ftp_rename", "comment": "항목(@{ftp_instance})중(@{file_type})(@{cur_file_name||cur_folder_name})로새이름(@{new_file_name||new_folder_name}),및뒤경로저장변수(@{rename_ftp_path})", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "ftp_instance", "title": "FTP연결객체", "name": "ftp_instance", "tip": "집행행파일/폴더의FTP연결객체", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "FileType", "formType": {"type": "RADIO"}, "key": "file_type", "title": "객체", "name": "file_type", "tip": "", "options": [{"label": "파일", "value": "file"}, {"label": "폴더", "value": "folder"}], "default": "file", "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "cur_file_name", "title": "파일명", "name": "cur_file_name", "tip": "출력입력대기파일", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.cur_file_name.show", "expression": "return $this.file_type.value == ''file''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "new_file_name", "title": "새파일명(안파일 확장자)", "name": "new_file_name", "tip": "출력입력새파일명,안파일 확장자", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.new_file_name.show", "expression": "return $this.file_type.value == ''file''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "cur_folder_name", "title": "폴더이름", "name": "cur_folder_name", "tip": "출력입력대기폴더", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.cur_folder_name.show", "expression": "return $this.file_type.value == ''folder''"}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "new_folder_name", "t