INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('240','Network.http_download','{"key": "Network.http_download", "title": "HTTP아래로드", "version": "1.0.1", "src": "astronverse.network.network.Network().http_download", "comment": "HTTP아래로드", "inputList": [{"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "url", "title": "아래로드주소", "name": "url", "tip": "", "default": "", "value": [{"type": "str", "value": ""}], "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "dst_dir", "title": "파일저장목록", "name": "dst_dir", "tip": "", "default": "", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "rename", "title": "지정파일명", "name": "rename", "tip": "안지정자동아래로드경로중의기본파일명, 기본파일명오류", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.rename.show", "expression": "return $this.state_type.value == ''create''"}], "required": false}, {"types": "StateType", "formType": {"type": "RADIO"}, "key": "state_type", "title": "목록안저장에서시", "name": "state_type", "tip": "설정파일저장목록안저장에서시의처리방식", "options": [{"label": "생성", "value": "create"}, {"label": "및오류", "value": "error"}], "default": "create", "required": false}, {"types": "FileExistenceType", "formType": {"type": "SELECT"}, "key": "exist_type", "title": "파일 존재시", "name": "exist_type", "tip": "설정목록파일이미저장에서시의처리방식", "options": [{"label": "생성파일", "value": "rename"}, {"label": "파일", "value": "overwrite"}, {"label": "건너뛰기저장", "value": "cancel"}], "default": "rename", "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "http_download_path", "title": "아래로드파일저장까지", "tip": "아래로드파일 경로저장까지변수중"}], "icon": "http-download", "helpManual": "아래로드지정URL(@{url})의파일저장까지지정목록(@{dst_dir})중,및저장아래로드경로까지변수(@{http_download_path})"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
