INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('277','System.paste_clip','{"key": "System.paste_clip", "title": "가져오기템플릿", "version": "1.0.1", "src": "astronverse.system.clipboard.Clipboard().paste_clip", "comment": "가져오기템플릿중의 @{content_type} , 및저장변수 @{output_content}", "inputList": [{"types": "ContentType", "formType": {"type": "SELECT"}, "key": "content_type", "title": "가져오기유형", "name": "content_type", "tip": "선택템플릿중가져오기의내용유형", "options": [{"label": "텍스트내용", "value": "msg"}, {"label": "HTML형식텍스트내용", "value": "html"}, {"label": "파일", "value": "file"}, {"label": "폴더", "value": "folder"}], "default": "msg", "required": true}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON_FILE", "params": {"filters": [], "file_type": "folder"}}, "key": "dst_path", "title": "저장경로", "name": "dst_path", "tip": "출력입력또는선택저장경로", "default": "", "dynamics": [{"key": "$this.dst_path.show", "expression": "return [''file'', ''folder''].includes($this.content_type.value)"}], "required": true}, {"types": "StateType", "formType": {"type": "RADIO"}, "key": "state_type", "title": "저장경로안저장에서시", "name": "state_type", "tip": "설정저장경로안저장에서시집행행의", "options": [{"label": "생성", "value": "create"}, {"label": "및오류", "value": "error"}], "default": "error", "dynamics": [{"key": "$this.state_type.show", "expression": "return [''folder'', ''file''].includes($this.content_type.value)"}], "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "dst_file_name", "title": "파일저장이름", "name": "dst_file_name", "tip": "출력입력저장의파일명, 안필요파일뒤, 로빈자동파일명", "default": "", "dynamics": [{"key": "$this.dst_file_name.show", "expression": "return $this.content_type.value == ''file''"}], "required": false}, {"types": "Str", "formType": {"type": "INPUT_VARIABLE_PYTHON"}, "key": "dst_folder_name", "title": "폴더저장이름", "name": "dst_folder_name", "tip": "출력입력저장의폴더이름, 로빈자동폴더이름", "default": "", "value": [{"type": "str", "value": ""}], "dynamics": [{"key": "$this.dst_folder_name.show", "expression": "return $this.content_type.value == ''folder''"}], "required": false}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "output_content", "title": "출력템플릿내용변수", "tip": "가져오기텍스트내용출력로텍스트변수, 가져오기파일/폴더출력로경로정보"}], "icon": "get-clipboard", "helpManual": "가져오기템플릿중의텍스트내용/파일/폴더, 및텍스트내용/파일폴더저장경로저장까지지정경로중"}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
