INSERT INTO `c_atom_meta_new` (`id`,`atom_key`,`atom_content`,`sort`,`create_time`,`update_time`)  VALUES ('285','TimeProcess.format_datetime','{"key": "TimeProcess.format_datetime", "title": "출력지정형식시간텍스트", "version": "1.0.2", "src": "astronverse.dataprocess.time.TimeProcess().format_datetime", "comment": "시간객체 @{time} 증명지정형식 @{format_type} 출력텍스트 @{format_datetime}", "inputList": [{"types": "Date", "formType": {"type": "INPUT_VARIABLE_PYTHON_DATETIME"}, "key": "time", "title": "시간객체", "name": "time", "tip": "", "required": true}, {"types": "TimeFormatType", "formType": {"type": "SELECT"}, "key": "format_type", "title": "시간형식", "name": "format_type", "tip": "", "options": [{"label": "년-월-일", "value": "%Y-%m-%d"}, {"label": "년-월-일 시:항목:초", "value": "%Y-%m-%d %H:%M:%S"}, {"label": "년-월-일 시:항목", "value": "%Y-%m-%d %H:%M"}, {"label": "년/월/일", "value": "%Y/%m/%d"}, {"label": "년/월/일 시:항목", "value": "%Y/%m/%d %H:%M"}, {"label": "년/월/일 시:항목:초", "value": "%Y/%m/%d %H:%M:%S"}, {"label": "년월일", "value": "%Y%m%d"}, {"label": "시:항목", "value": "%H:%M"}, {"label": "시:항목:초", "value": "%H:%M:%S"}, {"label": "주의제몇", "value": "%w"}, {"label": "년의제몇", "value": "%j"}, {"label": "년의제몇주", "value": "%W"}, {"label": "XXXX년XX월XX일", "value": "%Y년%m월%d일"}, {"label": "XXXX년XX월XX일 XX:XX", "value": "%Y년%m월%d일 %H:%M"}, {"label": "XXXX년XX월XX일 XX:XX:XX", "value": "%Y년%m월%d일 %H:%M:%S"}], "default": "%Y-%m-%d %H:%M:%S", "required": true}], "outputList": [{"types": "Str", "formType": {"type": "RESULT"}, "key": "format_datetime", "title": "시간텍스트", "tip": ""}], "icon": "output-formatted-time", "helpManual": ""}',NULL,'2025-10-11 14:12:21','2026-02-24 17:09:17');
